+        })
+        .map_err(|e| e.to_string())?
+        .len();
+
+    let in_progress = storage
+        .list_issues(&beads_rust::storage::ListFilters {
+            statuses: Some(vec![beads_rust::model::Status::InProgress]),
+            ..Default::default()
+        })
+        .map_err(|e| e.to_string())?
+        .len();
+
+    Ok((ready, open, in_progress))
